var e=[{id:`L2_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`헉…… 헉…… 쓰러트렸나?`,JPN:`はあ……はあ……倒したか？`,ENG:`*Huff... Huff...* Is he dead?`,TWN:`呼……呼…… 倒下了？`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`이건……? 피가 담긴 주사기?`,JPN:`これは……？　血が入った注射器？`,ENG:`Wait... A syringe with blood?`,TWN:`這是……？針筒的裡面是血？`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`놈들이 나에게 한 실험을 하바키에게도 저지른 건가?`,JPN:`奴らが私にした実験を覇吐にもしたのか？`,ENG:`The experiment they conducted on me... Did they also do it to Habaki?`,TWN:`他們也對幅木進行和我一樣的實驗嗎？`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`ELDER_NPC_NANAHARA_NAME`,text:{KOREA:`<color=#ff3636>나나하라…… 치후유……</color>`,JPN:`<color=#ff3636>七原……千冬……</color>`,ENG:`<color=#ff3636>Nanahara... Chifuyu...</color>`,TWN:`<color=#ff3636>七原…… 千冬……</color>`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`ELDER_NPC_NANAHARA_NAME`,text:{KOREA:`<color=#ff3636>너를…… 역신이 되게 두진…… 않…… 겠다……!</color>`,JPN:`<color=#ff3636>お前を……疫病神になるように……しておきは……しない……！</color>`,ENG:`<color=#ff3636>I... will not let... you... become... a Plague God...!</color>`,TWN:`<color=#ff3636>我……不會……讓你成為……瘟神……！</color>`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`마지막까지…… 말도 안 되는 헛소리를……!`,JPN:`最後まで……何をたわけたことを……！`,ENG:`Until the end... He keeps spouting this nonsense...!`,TWN:`死到臨頭……還在胡說八道什麼……！`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`큿, 팔이…… 안 움직여?`,JPN:`くっ、腕が……動かない？`,ENG:`Kgh...! My arm... I cannot move it...`,TWN:`唔，我的手臂……沒辦法動？`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`ELDER_NPC_NANAHARA_NAME`,text:{KOREA:`아니……?!`,JPN:`あ……！？`,ENG:`Huh...?!`,TWN:`怎麼會……？！`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`배반자에 어울리는 추악한 꼬락서니구나, 하바키.`,JPN:`裏切り者に相応しい醜い様だな、覇吐。`,ENG:`A befitting end for a traitor like you, Habaki.`,TWN:`看你這副狼狽樣，幅木，這就是叛徒的下場。`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`ELDER_NPC_NANAHARA_NAME`,text:{KOREA:`<color=#ff3636>사나에……</color>`,JPN:`<color=#ff3636>早苗……</color>`,ENG:`<color=#ff3636>Sanae...</color>`,TWN:`<color=#ff3636>早苗……</color>`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`ELDER_NPC_NANAHARA_NAME`,text:{KOREA:`<color=#ff3636>사나에-----!!!!!</color>`,JPN:`<color=#ff3636>早苗ーーーー！！！！！</color>`,ENG:`<color=#ff3636>SANAE!!!!!</color>`,TWN:`<color=#ff3636>早苗-----！！！！！</color>`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`더 이상 이승에 네놈이 발붙일 자리는 없다.`,JPN:`もうこの世にお前がいる場所はない。`,ENG:`There is no place for you in this world anymore.`,TWN:`現世已經沒有你的立足之地。`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`늦지 않아서 다행입니다.`,JPN:`手遅れにならずに済んで幸いでした。`,ENG:`Thank goodness I wasn't late.`,TWN:`幸好有趕上。`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`하야미 공…… 그렇게 다치신 몸으로…… 여기까지 오신 겁니까?`,JPN:`速水殿……そんな体で……ここまで来られたのですか？`,ENG:`Dame Sanae... Did you come all this way... in that state?`,TWN:`速水……你自己也受傷……怎麼還跑到這裡來？`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`걱정하실 정도는 아닙니다.`,JPN:`ご心配には及びません。`,ENG:`It is not as bad as it seems.`,TWN:`不必擔心，沒那麼嚴重。`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`그나저나, 역귀가 된 자에게 다친 팔로 맞서다니 장하시군요.`,JPN:`それより、疫鬼になった者に怪我した腕で立ち向かうとは、ご立派です。`,ENG:`Anyway, it was impressive to see you fight against the Plagued Ghost with only one arm.`,TWN:`倒是您竟然用受傷的手臂對付變成疫鬼之人，真是佩服。`},stage:{bg:`NEWTOWN_NIGHT`,slots:{L:null,C:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};